import{_ as e,o as t,c as l,ag as i}from"./chunks/framework.eQLvDOR_.js";const g=JSON.parse('{"title":"Agent 评估 (Agent Evals)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/concepts/agent-evals.md","filePath":"wiki/concepts/agent-evals.md","lastUpdated":null}'),n={name:"wiki/concepts/agent-evals.md"};function r(o,a,s,c,d,h){return t(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="agent-评估-agent-evals" tabindex="-1">Agent 评估 (Agent Evals) <a class="header-anchor" href="#agent-评估-agent-evals" aria-label="Permalink to &quot;Agent 评估 (Agent Evals)&quot;">​</a></h1><h2 id="核心定义" tabindex="-1">核心定义 <a class="header-anchor" href="#核心定义" aria-label="Permalink to &quot;核心定义&quot;">​</a></h2><p>在构建 AI Agent 时，用于衡量和验证其行为、工具调用准确率以及任务完成率的系统化评估基准。</p><h2 id="为什么重要" tabindex="-1">为什么重要 <a class="header-anchor" href="#为什么重要" aria-label="Permalink to &quot;为什么重要&quot;">​</a></h2><ul><li>在快速迭代的 Agent 框架中，没有 Eval 就等于“盲飞”。</li><li>帮助开发者区分“表面看起来工作”与“在边缘场景依然稳定”。</li><li>它是将 Agent 从玩具 (Toy) 变成生产级工具 (Production-grade) 的关键分水岭。</li></ul><h2 id="实践要点" tabindex="-1">实践要点 <a class="header-anchor" href="#实践要点" aria-label="Permalink to &quot;实践要点&quot;">​</a></h2><ul><li>针对 Agent 的每项核心 Skill 构建测试用例集。</li><li>引入自动化评估流程，在修改 Prompt 或工具 Schema 后即刻运行。</li><li>不要只关注成功率，同时衡量 Token 消耗量、调用耗时等效率指标。</li></ul><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li>[[durable-agent-primitives]]</li><li>[[agent-architecture]]</li></ul>',9)])])}const _=e(n,[["render",r]]);export{g as __pageData,_ as default};
